Adding a metrics module is a great idea for monitoring the performance and health of your ETL pipeline. This will help you track key performance indicators (KPIs) such as execution time, success rates, error counts, and more. Here’s how you can implement this:

### Metrics Module

#### 1. **Define Metric Types**

First, define different types of metrics that are relevant to your ETL pipeline.

```python
from enum import Enum

class MetricType(Enum):
    COUNT = "count"
    DURATION = "duration"
    SUCCESS_RATE = "success_rate"
```

#### 2. **Metric Class**

Create a base class for metrics and specific metric classes for different types of measurements.

```python
import time
from typing import Dict, Any

class Metric:
    def __init__(self, name: str):
        self.name = name

    def record(self, value: Any) -> None:
        raise NotImplementedError("Subclasses should implement this method.")

    def get_value(self) -> Any:
        raise NotImplementedError("Subclasses should implement this method.")

class CountMetric(Metric):
    def __init__(self, name: str):
        super().__init__(name)
        self.count = 0

    def record(self, value: int = 1) -> None:
        self.count += value

    def get_value(self) -> int:
        return self.count

class DurationMetric(Metric):
    def __init__(self, name: str):
        super().__init__(name)
        self.start_time = None
        self.durations = []

    def start(self) -> None:
        self.start_time = time.time()

    def stop(self) -> float:
        if self.start_time is not None:
            duration = time.time() - self.start_time
            self.durations.append(duration)
            return duration
        else:
            raise ValueError("DurationMetric must be started before stopping.")

    def get_value(self) -> Dict[str, Any]:
        total_duration = sum(self.durations)
        average_duration = total_duration / len(self.durations) if self.durations else 0.0
        return {
            "total": total_duration,
            "average": average_duration,
            "count": len(self.durations),
        }

class SuccessRateMetric(Metric):
    def __init__(self, name: str):
        super().__init__(name)
        self.success_count = 0
        self.failure_count = 0

    def record_success(self) -> None:
        self.success_count += 1

    def record_failure(self) -> None:
        self.failure_count += 1

    def get_value(self) -> float:
        total_attempts = self.success_count + self.failure_count
        if total_attempts == 0:
            return 0.0
        else:
            success_rate = (self.success_count / total_attempts) * 100
            return success_rate
```

#### 3. **Metrics Registry**

Create a registry to manage and collect metrics.

```python
class MetricsRegistry:
    def __init__(self):
        self.metrics: Dict[str, Metric] = {}

    def register(self, metric_type: MetricType, name: str) -> Metric:
        if metric_type == MetricType.COUNT:
            metric = CountMetric(name)
        elif metric_type == MetricType.DURATION:
            metric = DurationMetric(name)
        elif metric_type == MetricType.SUCCESS_RATE:
            metric = SuccessRateMetric(name)
        else:
            raise ValueError(f"Unsupported metric type: {metric_type}")

        self.metrics[name] = metric
        return metric

    def get(self, name: str) -> Metric:
        if name in self.metrics:
            return self.metrics[name]
        else:
            raise KeyError(f"No metric registered with the name '{name}'")
```

